 20→void ALFPWorldMapPlayerController::BeginPlay()
 21→{
 22→	Super::BeginPlay();
 23→
 24→	// 设置输入模式
 25→	FInputModeGameAndUI InputMode;
 26→	InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
