 38→
 39→	FVector SpawnLocation(Position.X, Position.Y, 0.f);
 40→	FActorSpawnParameters SpawnParams;
 41→	SpawnParams.Owner = this;
 42→
 43→	ALFPWorldMapNode* NewNode = GetWorld()->SpawnActor<ALFPWorldMapNode>(
 44→		NodeActorClass, SpawnLocation, FRotator::ZeroRotator, SpawnParams);
 45→
 46→	if (!NewNode) return nullptr;
