140→ALFPWorldMapEdge* ALFPWorldMapManager::AddEdge(int32 FromID, int32 ToID, int32 TurnCost)
141→{
142→	// 验证节点存在
143→	if (!NodeMap.Contains(FromID) || !NodeMap.Contains(ToID))
144→	{
145→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 节点 %d 或 %d 不存在"), FromID, ToID);
146→		return nullptr;
147→	}
148→
149→	// 不能自连
150→	if (FromID == ToID)
151→	{
152→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 不能自连节点 %d"), FromID);
153→		return nullptr;
154→	}
155→
156→	FIntPoint Key = MakeEdgeKey(FromID, ToID);
157→
158→	// 检查重复
159→	if (EdgeMap.Contains(Key))
160→	{
161→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 边 %d-%d 已存在"), FromID, ToID);
162→		return EdgeMap[Key];
163→	}
164→
165→	if (!EdgeActorClass)
166→	{
167→		UE_LOG(LogTemp, Error, TEXT("AddEdge: EdgeActorClass 未配置"));
168→		return nullptr;
169→	}
170→
171→	FActorSpawnParameters SpawnParams;
172→	SpawnParams.Owner = this;
173→
174→	ALFPWorldMapEdge* NewEdge = GetWorld()->SpawnActor<ALFPWorldMapEdge>(
175→		EdgeActorClass, FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
176→
177→	if (!NewEdge) return nullptr;
178→
179→	NewEdge->FromNodeID = FromID;
180→	NewEdge->ToNodeID = ToID;
181→	NewEdge->TravelTurnCost = TurnCost;
182→	NewEdge->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
183→
184→	// 设置边精灵
185→	if (EdgeSprite)
186→	{
187→		NewEdge->SetEdgeSprite(EdgeSprite);
188→	}
189→
190→	// 更新视觉位置
191→	ALFPWorldMapNode* FromNode = NodeMap[FromID];
192→	ALFPWorldMapNode* ToNode = NodeMap[ToID];
193→	NewEdge->UpdateVisualPosition(FromNode->GetActorLocation(), ToNode->GetActorLocation());
194→
195→	// 存储
196→	EdgeMap.Add(Key, NewEdge);
197→
198→	// 更新邻接表（双向）
199→	AdjacencyList.FindOrAdd(FromID).Add(ToID);
200→	AdjacencyList.FindOrAdd(ToID).Add(FromID);
201→
202→	// 更新节点-边索引
203→	NodeEdgeIndex.FindOrAdd(FromID).Add(Key);
204→	NodeEdgeIndex.FindOrAdd(ToID).Add(Key);
205→
206→	return NewEdge;
207→}
