543→// ============== 迷雾系统 ==============
544→
545→TSet<int32> ALFPWorldMapManager::GetNodesWithinGraphDistance(int32 StartNodeID, int32 MaxDistance) const
546→{
547→	TSet<int32> Result;
548→
549→	if (!AdjacencyList.Contains(StartNodeID)) return Result;
550→
551→	// BFS
552→	TQueue<TPair<int32, int32>> Queue; // <NodeID, Distance>
553→	TSet<int32> Visited;
554→
555→	Queue.Enqueue(TPair<int32, int32>(StartNodeID, 0));
556→	Visited.Add(StartNodeID);
557→
558→	while (!Queue.IsEmpty())
559→	{
560→		TPair<int32, int32> Current;
561→		Queue.Dequeue(Current);
562→
563→		int32 CurrentID = Current.Key;
564→		int32 CurrentDist = Current.Value;
565→
566→		Result.Add(CurrentID);
567→
568→		if (CurrentDist >= MaxDistance) continue;
569→
570→		if (const TSet<int32>* Neighbors = AdjacencyList.Find(CurrentID))
571→		{
572→			for (int32 NeighborID : *Neighbors)
573→			{
574→				if (!Visited.Contains(NeighborID))
575→				{
576→					Visited.Add(NeighborID);
577→					Queue.Enqueue(TPair<int32, int32>(NeighborID, CurrentDist + 1));
578→				}
579→			}
580→		}
581→	}
582→
583→	return Result;
584→}
