586→void ALFPWorldMapManager::UpdateFog()
587→{
588→	if (!PlayerState) return;
589→
590→	// 获取视野范围内的节点
591→	TSet<int32> VisibleNodes = GetNodesWithinGraphDistance(PlayerState->CurrentNodeID, FogVisionRange);
592→
593→	// 添加到永久揭露集合
594→	for (int32 NodeID : VisibleNodes)
595→	{
596→		PlayerState->RevealedNodeIDs.Add(NodeID);
597→	}
598→
599→	// 更新所有节点的视觉状态
600→	for (auto& Pair : NodeMap)
601→	{
602→		if (!Pair.Value) continue;
603→
604→		Pair.Value->bIsRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key);
605→		Pair.Value->UpdateVisualState();
606→	}
607→
608→	// 更新边的可见性（两端都揭露才可见）
609→	for (auto& Pair : EdgeMap)
610→	{
611→		if (!Pair.Value) continue;
612→
613→		bool bBothRevealed = PlayerState->RevealedNodeIDs.Contains(Pair.Key.X)
614→			&& PlayerState->RevealedNodeIDs.Contains(Pair.Key.Y);
615→		Pair.Value->SetActorHiddenInGame(!bBothRevealed);
616→	}
617→}
