636→bool ALFPWorldMapManager::MovePlayer(int32 TargetNodeID)
637→{
638→	if (!PlayerState) return false;
639→
640→	bool bMoved = PlayerState->MoveToNode(TargetNodeID, this);
641→
642→	if (bMoved)
643→	{
644→		// 更新迷雾
645→		UpdateFog();
646→
647→		// 触发节点事件（首次进入未触发的节点）
648→		ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
649→		if (TargetNode && !TargetNode->bHasBeenTriggered)
650→		{
651→			// 标记节点类型决定是否首次触发
652→			switch (TargetNode->NodeType)
653→			{
654→			case ELFPWorldNodeType::WNT_Battle:
655→			case ELFPWorldNodeType::WNT_Event:
656→			case ELFPWorldNodeType::WNT_Boss:
657→				TargetNode->bHasBeenTriggered = true;
658→				TargetNode->UpdateVisualState();
659→				break;
660→			default:
661→				// 商店、城镇、任务NPC、技能节点可反复进入
662→				break;
663→			}
664→		}
665→
666→		// 回合压力检查
667→		if (PlayerState->IsPastPressureThreshold())
668→		{
669→			UE_LOG(LogTemp, Warning, TEXT("回合压力: 已超过 %d 回合阈值！当前 %d 回合"),
670→				PlayerState->TurnPressureThreshold, PlayerState->CurrentTurn);
671→		}
672→	}
673→
674→	return bMoved;
675→}
