	// 是否胜利
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bVictory = false;

	// 是否逃跑
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bEscaped = false;

	// 战斗中捕获的单位列表（背叛系统触发）
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	TArray<FLFPUnitEntry> CapturedUnits;

	// 是否有有效结果
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bIsValid = false;
