243→void ALFPTacticsUnit::UpdateMoveAnimation(float Value)
244→{
245→    if (CurrentPathIndex < 0 || CurrentPathIndex >= MovePath.Num() - 1) return;
246→
247→    // 获取当前和下一个格子
248→    ALFPHexTile* CurrentTile = MovePath[CurrentPathIndex];
249→    ALFPHexTile* NextTile = MovePath[CurrentPathIndex + 1];
250→
251→    if (!CurrentTile || !NextTile) return;
252→
253→    // 计算位置
254→    FVector StartPos = CurrentTile->GetActorLocation() + FVector(0, 0, 50);
255→    FVector EndPos = NextTile->GetActorLocation() + FVector(0, 0, 50);
256→
257→    // 应用插值
258→    FVector NewLocation = FMath::Lerp(StartPos, EndPos, Value);
259→    SetActorLocation(NewLocation);
260→
261→    // 更新朝向
262→    FVector Direction = (EndPos - StartPos).GetSafeNormal();
263→    if (!Direction.IsNearlyZero())
264→    {
265→        FRotator NewRotation = Direction.Rotation();
266→        SpriteComponent->SetWorldRotation(NewRotation);
267→    }
268→
269→    // 检查是否移动到下一段
270→    if (Value >= 1.0f)
271→    {
272→        CurrentPathIndex++;
273→        MoveProgress = 0.0f;
274→
275→        // 更新当前坐标
276→        if (CurrentPathIndex < MovePath.Num())
277→        {
278→            SetCurrentCoordinates(MovePath[CurrentPathIndex]->GetCoordinates());
279→        }
280→
281→        // 如果还有下一段路径，重新开始时间线
282→        if (CurrentPathIndex < MovePath.Num() - 1)
283→        {
284→            //MoveTimeline->PlayFromStart();
285→        }
286→        else
287→        {
288→            FinishMove();
289→        }
290→    }
291→}
