 6→void ULFPWorldMapPlayerState::Initialize(int32 StartNodeID)
 7→{
 8→	CurrentNodeID = StartNodeID;
 9→	CurrentTurn = 0;
10→	VisitedNodeIDs.Empty();
11→	RevealedNodeIDs.Empty();
12→
