545→void ALFPTacticsUnit::ApplyDamageToTarget(ALFPTacticsUnit* Target)
546→{
547→    if (!Target || Target->bIsDead) return;
548→
549→    // 基础伤害计算
550→    int32 Damage = AttackPower;
551→
552→    // 伤害随机浮动（10% 范围）
