675→float ALFPTacticsUnit::CalculateThreatValue(ALFPTacticsUnit* Target)
676→{
677→    // 威胁值 = 目标攻击力
678→    float ThreatValue = Target->GetAttackPower();
679→
680→    // 距离因素（越近威胁越大）
681→    int32 Distance = FLFPHexCoordinates::Distance(
682→        GetCurrentCoordinates(),
683→        Target->GetCurrentCoordinates()
684→    );
685→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
686→
687→    //// 应用行为数据
688→    //if (BehaviorData)
689→    //{
690→    //    if (BehaviorData->bPrioritizeWeakTargets)
691→    //    {
692→    //        // 增加对低血量目标的权重
693→    //        float HealthRatio = (float)Target->GetCurrentHealth() / Target->GetMaxHealth();
694→    //        // 血量越低，威胁值越高
695→    //    }
696→
697→    //    // 应用攻击性系数
698→    //    ThreatValue *= BehaviorData->Aggressiveness;
699→    //}
700→
701→    return ThreatValue * DistanceFactor;
702→}
