759→TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
760→{
761→    TArray<ALFPHexTile*> AttackRangeTiles;
762→
763→    if (ALFPHexGridManager* GridManager = GetGridManager())
764→    {
765→        // 近战攻击范围
766→        if (bMeleeAttack)
767→        {
768→            // 获取相邻格子
769→            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
770→            for (const FLFPHexCoordinates& Coord : Neighbors)
771→            {
772→                FLFPHexCoordinates Key(Coord.Q, Coord.R);
773→                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
774→                {
775→                    AttackRangeTiles.Add(Tile);
776→                }
777→            }
778→        }
779→        // 远程攻击范围
780→        else
781→        {
782→            // 获取攻击范围内的所有格子
783→            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
784→
785→            for (ALFPHexTile* Tile : TilesInRange)
786→            {
787→                AttackRangeTiles.Add(Tile);
788→            }
789→        }
790→    }
791→
792→    return AttackRangeTiles;
793→}
