795→bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
796→{
797→    if (!Target || !Target->GetCurrentTile()) return false;
798→
799→    // 计算距离
800→    int32 Distance = FLFPHexCoordinates::Distance(
801→        CurrentCoordinates,
802→        Target->GetCurrentCoordinates()
803→    );
804→
805→    // 近战攻击判定
806→    if (bMeleeAttack)
807→    {
808→        return Distance == 1; // 相邻格子
809→    }
810→    // 远程攻击判定
811→    else
812→    {
813→        return Distance >= 2 && Distance <= AttackRange;
814→    }
