 82→void ALFPTurnManager::EndCurrentRound()
 83→{
 84→    bIsInRound = false;
 85→
 86→    SetPhase(EBattlePhase::BP_RoundEnd);
 87→
 88→    // 通知玩家本回合结束
 89→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
 90→    {
 91→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
 92→        {
 93→            PC->OnRoundEnded(CurrentRound);
 94→        }
 95→    }
 96→
 97→    // 添加延迟后开始新回合
 98→    FTimerHandle TimerHandle;
 99→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
100→}
