264→void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
265→{
266→    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
267→
268→    if (Plan.bIsValid && Plan.PlannedSkill)
269→    {
270→        // 在原定目标格子释放技能（即使目标已死亡）
271→        // AP 已在规划阶段 AllocateEnemySkills 中扣除
272→        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
273→    }
274→
275→    // 清除头顶技能图标
276→    Unit->ClearActionPlan();
277→
278→    // 短延时后结束回合（让玩家看到技能效果）
279→    FTimerHandle TimerHandle;
280→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
281→    {
282→        Unit->SetHasActed(true);
283→        PassTurn();
284→    }, 0.5f, false);
285→}
