301→void ALFPTurnManager::PassTurn()
302→{
303→    if (!CurrentUnit || TurnOrderUnits.IsEmpty())
304→    {
305→        return;
306→    }
307→
308→    // 结束当前单位回合
309→    EndUnitTurn(CurrentUnit);
310→
311→    // 找到下一个未行动的单位
312→    int32 CurrentIndex = TurnOrderUnits.Find(CurrentUnit);
313→    int32 NextIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
314→
315→    // 检查所有单位是否行动完毕
316→    bool TurnOrderUnitsActed = true;
317→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
318→    {
319→        if (Unit && Unit->IsAlive() && !Unit->HasActed())
320→        {
321→            TurnOrderUnitsActed = false;
322→            break;
323→        }
324→    }
325→
326→    if (TurnOrderUnitsActed)
327→    {
328→        // 所有单位行动完毕，结束回合
329→        EndCurrentRound();
330→    }
331→    else
332→    {
333→        // 寻找下一个未行动单位
334→        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
335→        {
336→            int32 Index = (NextIndex + i) % TurnOrderUnits.Num();
337→            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
338→
339→            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
340→            {
341→                BeginUnitTurn(NextUnit);
342→                return;
343→            }
344→        }
345→
346→        // 没有找到未行动单位，结束回合
347→        EndCurrentRound();
348→    }
349→}
