 25→void ALFPTurnManager::StartGame()
 26→{
 27→    // 收集所有单位
 28→    TArray<AActor*> FoundActors;
 29→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 30→
 31→    // 转换为战术单位数组
 32→    for (AActor* Actor : FoundActors)
 33→    {
 34→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 35→        {
 36→            TurnOrderUnits.Add(Unit);
 37→        }
 38→    }
 39→
 40→    // 添加延迟后开始第一回合
 41→    FTimerHandle TimerHandle;
 42→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
 43→
 44→    // 初始化阵营 AP
 45→    FactionCurrentAP.Add(EUnitAffiliation::UA_Player, FactionInitialAP);
 46→    FactionCurrentAP.Add(EUnitAffiliation::UA_Enemy, FactionInitialAP);
 47→    FactionCurrentAP.Add(EUnitAffiliation::UA_Neutral, FactionInitialAP);
 48→}
