458→    // 按有效优先级降序排序
459→    Candidates.Sort([](const FSkillCandidate& A, const FSkillCandidate& B) {
460→        return A.EffectivePriority > B.EffectivePriority;
461→    });
462→
463→    // 依次分配：如果阵营AP足够且该单位尚未分配
464→    for (const FSkillCandidate& Candidate : Candidates)
465→    {
466→        // 该单位已分配过技能，跳过
467→        if (AllocatedSkills.Contains(Candidate.Unit)) continue;
468→
469→        // 检查阵营AP是否足够
470→        if (HasEnoughFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost))
471→        {
472→            AllocatedSkills.Add(Candidate.Unit, Candidate.Skill);
473→            ConsumeFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost);
474→        }
475→    }
476→
477→    // 未分配到AP技能的敌人会在 CreateActionPlan 中 fallback 到默认攻击
478→}
